enum TransactionError: LocalizedError {
    case insufficientFunds
    case invalidAmount
    case accountNotFound
    case accountInactive
    case transactionLimitExceeded
    case duplicateTransaction
    case integrityCheckFailed
    
    var errorDescription: String? {
        switch self {
        case .insufficientFunds: return "Insufficient funds to complete this transaction."
        case .invalidAmount: return "Transaction amount is invalid."
        case .accountNotFound: return "Account not found."
        case .accountInactive: return "Account is inactive."
        case .transactionLimitExceeded: return "Transaction limit exceeded."
        case .duplicateTransaction: return "Duplicate transaction detected."
        case .integrityCheckFailed: return "Transaction integrity check failed."
        }
    }
}

protocol TransactionProcessing {
    func processTransaction(_ transaction: Transaction) async throws -> Transaction
    func validateTransaction(_ transaction: Transaction) throws
}

final class TransactionProcessor: TransactionProcessing {
    
    static let shared = TransactionProcessor()
    
    private let dailyTransactionLimit: Decimal = 50000.00
    private let singleTransactionLimit: Decimal = 10000.00
    private let encryption = EncryptionService.shared
    
    private var processedTransactionHashes: Set<String> = []
    private let processingQueue = DispatchQueue(label: "com.bankingapp.transaction.processing", qos: .userInitiated)
    
    private init() {}
    
    func validateTransaction(_ transaction: Transaction) throws {
        // Validate amount
        guard transaction.amount > 0 else {
            throw TransactionError.invalidAmount
        }
        
        // Check single transaction limit
        guard transaction.amount <= singleTransactionLimit else {
            throw TransactionError.transactionLimitExceeded
        }
        
        // Check for duplicate transactions
        let transactionHash = generateTransactionHash(transaction)
        guard !processedTransactionHashes.contains(transactionHash) else {
            throw TransactionError.duplicateTransaction
        }
    }
    
    func processTransaction(_ transaction: Transaction) async throws -> Transaction {
        // Validate first
        try validateTransaction(transaction)
        
        // Simulate network/processing delay
        try await Task.sleep(nanoseconds: 500_000_000)
        
        var processedTransaction = transaction
        
        do {
            // Verify transaction integrity
            try verifyTransactionIntegrity(transaction)
            
            // Log the transaction securely
            try await logTransaction(transaction)
            
            // Mark as completed
            processedTransaction.status = .completed
            
            // Store the hash to prevent duplicates
            let hash = generateTransactionHash(transaction)
            processedTransactionHashes.insert(hash)
            
        } catch {
            processedTransaction.status = .failed
            throw error
        }
        
        return processedTransaction
    }
    
    private func generateTransactionHash(_ transaction: Transaction) -> String {
        let data = "\(transaction.id)\(transaction.amount)\(transaction.fromAccountId)\(transaction.timestamp.timeIntervalSince1970)"
        return encryption.hashString(data)
    }
    
    private func verifyTransactionIntegrity(_ transaction: Transaction) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        guard let data = try? encoder.encode(transaction) else {
            throw TransactionError.integrityCheckFailed
        }
        
        // Generate and verify HMAC
        let hmac = try encryption.generateHMAC(for: data)
        let isValid = try encryption.verifyHMAC(hmac, for: data)
        
        guard isValid else {
            throw TransactionError.integrityCheckFailed
        }
    }
    
    private func logTransaction(_ transaction: Transaction) async throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(transaction)
        let _ = try encryption.encrypt(data)
        // In production, this encrypted data would be sent to a secure logging service
    }
}

// MARK: - Account Manager

final class AccountManager: ObservableObject {
    
    static let shared = AccountManager()
    
    @Published private(set) var accounts: [Account] = []
    @Published private(set) var transactions: [Transaction] = []
    @Published private(set) var isLoading: Bool = false
    @Published var errorMessage: String?
    
    private let transactionProcessor = TransactionProcessor.shared
    private let secureStorage = SecureStorage.shared
    private let accountsStorageKey = "stored_accounts"
    private let transactionsStorageKey = "stored_transactions"
    
    private init() {
        loadStoredData()
    }
    
    // MARK: - Account Management
    
    func createAccount(holderName: String, initialDeposit: Decimal, currency: Currency = .usd) -> Account {
        let accountNumber = generateAccountNumber()
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountHolderName: holderName,
            balance: initialDeposit,
            currency: currency,
            createdAt: Date(),
            isActive: true
        )
        
        accounts.append(account)
        saveAccounts()
        return account
    }
    
    func getAccount(byId id: String) -> Account? {
        return accounts.first { $0.id == id }
    }
    
    func getTotalBalance(currency: Currency = .usd) -> Decimal {
        return accounts
            .filter { $0.currency == currency && $0.isActive }
            .reduce(0) { $0 + $1.balance }
    }
    
    func getFormattedTotalBalance(currency: Currency = .usd) -> String {
        let total = getTotalBalance(currency: currency)
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency.rawValue
        return formatter.string(from: total as NSDecimalNumber) ?? "\(total)"
    }
    
    // MARK: - Transaction Processing
    
    func deposit(accountId: String, amount: Decimal, description: String = "Deposit") async throws {
        guard var account = getAccount(byId: accountId) else {
            throw TransactionError.accountNotFound
        }
        
        guard account.isActive else {
            throw TransactionError.accountInactive
        }
        
        let transaction = Transaction(
            type: .deposit,
            amount: amount,
            currency: account.currency,
            fromAccountId: accountId,
            description: description
        )
        
        let processedTransaction = try await transactionProcessor.processTransaction(transaction)
        
        await MainActor.run {
            account.balance += amount
            updateAccount(account)
            transactions.insert(processedTransaction, at: 0)
            saveTransactions()
        }
    }
    
    func withdraw(accountId: String, amount: Decimal, description: String = "Withdrawal") async throws {
        guard var account = getAccount(byId: accountId) else {
            throw TransactionError.accountNotFound
        }
        
        guard account.isActive else {
            throw TransactionError.accountInactive
        }
        
        guard account.balance >= amount else {
            throw TransactionError.insufficientFunds
        }
        
        let transaction = Transaction(
            type: .withdrawal,
            amount: amount,
            currency: account.currency,
            fromAccountId: accountId,
            description: description
        )
        
        let processedTransaction = try await transactionProcessor.processTransaction(transaction)
        
        await MainActor.run {
            account.balance -= amount
            updateAccount(account)
            transactions.insert(processedTransaction, at: 0)
            saveTransactions()
        }
    }
    
    func transfer(fromAccountId: String, toAccountId: String, amount: Decimal, description: String = "Transfer") async throws {
        guard var fromAccount = getAccount(byId: fromAccountId) else {
            throw TransactionError.accountNotFound
        }
        
        guard var toAccount = getAccount(byId: toAccountId) else {
            throw TransactionError.accountNotFound
        }
        
        guard fromAccount.isActive && toAccount.isActive else {
            throw TransactionError.accountInactive
        }
        
        guard fromAccount.balance >= amount else {
            throw TransactionError.insufficientFunds
        }
        
        let transaction = Transaction(
            type: .transfer,
            amount: amount,
            currency: fromAccount.currency,
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            description: description
        )
        
        let processedTransaction = try await transactionProcessor.processTransaction(transaction)
        
        await MainActor.run {
            fromAccount.balance -= amount
            toAccount.balance += amount
            updateAccount(fromAccount)
            updateAccount(toAccount)
            transactions.insert(processedTransaction, at: 0)
            saveTransactions()
        }
    }
    
    func getTransactions(forAccountId accountId: String) -> [Transaction] {
        return transactions.filter {
            $0.fromAccountId == accountId || $0.toAccountId == accountId
        }
    }
    
    func getRecentTransactions(limit: Int = 10) -> [Transaction] {
        return Array(transactions.prefix(limit))
    }
    
    // MARK: - Private Helpers
    
    private func updateAccount(_ account: Account) {
        if let index = accounts.firstIndex(where: { $0.id == account.id }) {
            accounts[index] = account
            saveAccounts()
        }
    }
    
    private func generateAccountNumber() -> String {
        let digits = (0..<12).map { _ in String(Int.random(in: 0...9)) }.joined()
        return digits
    }
    
    private func saveAccounts() {
        try? secureStorage.saveSecurely(accounts, forKey: accountsStorageKey)
    }
    
    private func saveTransactions() {
        try? secureStorage.saveSecurely(transactions, forKey: transactionsStorageKey)
    }
    
    private func loadStoredData() {
        if let storedAccounts = try? secureStorage.loadSecurely([Account].self, forKey: accountsStorageKey) {
            accounts = storedAccounts
        }
        
        if let storedTransactions = try? secureStorage.loadSecurely([Transaction].self, forKey: transactionsStorageKey) {
            transactions = storedTransactions
        }
    }
    
    // MARK: - Demo Data
    
    func loadDemoData() {
        guard accounts.isEmpty else { return }
        
        let _ = createAccount(holderName: "John Smith", initialDeposit: 15420.50)
        let _ = createAccount(holderName: "John Smith", initialDeposit: 8750.25)
        let _ = createAccount(holderName: "John Smith", initialDeposit: 32100.00)
    }
}

