        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = transaction.currency.rawValue
        let formatted = formatter.string(from: transaction.amount as NSDecimalNumber) ?? "\(transaction.amount)"
        return "\(amountPrefix)\(formatted)"
    }
    
    private var formattedDate: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: transaction.timestamp)
    }
    
    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: icon)
                .font(.title2)
                .foregroundColor(iconColor)
                .frame(width: 40, height: 40)
                .background(iconColor.opacity(0.1))
                .clipShape(Circle())
            
            VStack(alignment: .leading, spacing: 2) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                
                Text(formattedDate)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 2) {
                Text(formattedAmount)
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(amountColor)
                
                Text(transaction.status.rawValue)
                    .font(.caption2)
                    .foregroundColor(statusColor)
            }
        }
        .padding(.vertical, 8)
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
}

// MARK: - New Transaction View

struct NewTransactionView: View {
    
    @Environment(\.dismiss) private var dismiss
    @StateObject private var accountManager = AccountManager.shared
    
    @State private var selectedType: TransactionType = .deposit
    @State private var amount: String = ""
    @State private var description: String = ""
    @State private var selectedFromAccountIndex: Int = 0
    @State private var selectedToAccountIndex: Int = 0
    @State private var isProcessing = false
    @State private var showResult = false
    @State private var resultMessage = ""
    @State private var resultIsSuccess = false
    
    var body: some View {
        NavigationView {
            Form {
                // Transaction Type
                Section("Transaction Type") {
                    Picker("Type", selection: $selectedType) {
                        ForEach(TransactionType.allCases, id: \.self) { type in
                            Text(type.rawValue).tag(type)
                        }
                    }
                    .pickerStyle(.segmented)
                }
                
                // From Account
                Section("From Account") {
                    if !accountManager.accounts.isEmpty {
                        Picker("Account", selection: $selectedFromAccountIndex) {
                            ForEach(0..<accountManager.accounts.count, id: \.self) { index in
                                let account = accountManager.accounts[index]
                                Text("\(account.maskedAccountNumber) - \(account.formattedBalance)")
                                    .tag(index)
                            }
                        }
                    }
                }
                
                // To Account (for transfers)
                if selectedType == .transfer {
                    Section("To Account") {
                        Picker("Account", selection: $selectedToAccountIndex) {
                            ForEach(0..<accountManager.accounts.count, id: \.self) { index in
                                let account = accountManager.accounts[index]
                                Text("\(account.maskedAccountNumber) - \(account.formattedBalance)")
                                    .tag(index)
                            }
                        }
                    }
                }
                
                // Amount
                Section("Amount") {
                    HStack {
                        Text("$")
                            .font(.title2)
                            .foregroundColor(.secondary)
                        TextField("0.00", text: $amount)
                            .keyboardType(.decimalPad)
                            .font(.title2)
                    }
                }
                
                // Description
                Section("Description") {
                    TextField("Enter description", text: $description)
                }
                
                // Submit Button
                Section {
                    Button(action: processTransaction) {
                        HStack {
                            if isProcessing {
                                ProgressView()
                                    .tint(.white)
                            }
                            Text(isProcessing ? "Processing..." : "Submit Transaction")
                                .fontWeight(.semibold)
                        }
                        .frame(maxWidth: .infinity)
                    }
                    .disabled(amount.isEmpty || isProcessing || accountManager.accounts.isEmpty)
                    .listRowBackground(Color.blue)
                    .foregroundColor(.white)
                }
                
                // Security Info
                Section {
                    HStack {
                        Image(systemName: "lock.shield.fill")
                            .foregroundColor(.green)
                        Text("This transaction is encrypted and secured with AES-256-GCM encryption.")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle("New Transaction")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert(resultIsSuccess ? "Success" : "Error", isPresented: $showResult) {
                Button("OK") {
                    if resultIsSuccess { dismiss() }
                }
            } message: {
                Text(resultMessage)
            }
        }
    }
    
    private func processTransaction() {
        guard let decimalAmount = Decimal(string: amount), decimalAmount > 0 else {
            resultMessage = "Please enter a valid amount."
            resultIsSuccess = false
            showResult = true
            return
        }
        
        guard !accountManager.accounts.isEmpty else {
            resultMessage = "No accounts available."
            resultIsSuccess = false
            showResult = true
            return
        }
        
        isProcessing = true
        
        let fromAccount = accountManager.accounts[selectedFromAccountIndex]
        let desc = description.isEmpty ? selectedType.rawValue : description
        
        Task {
            do {
                switch selectedType {
                case .deposit:
                    try await accountManager.deposit(accountId: fromAccount.id, amount: decimalAmount, description: desc)
                case .withdrawal:
                    try await accountManager.withdraw(accountId: fromAccount.id, amount: decimalAmount, description: desc)
                case .transfer:
                    let toAccount = accountManager.accounts[selectedToAccountIndex]
                    try await accountManager.transfer(fromAccountId: fromAccount.id, toAccountId: toAccount.id, amount: decimalAmount, description: desc)
                case .payment:
                    try await accountManager.withdraw(accountId: fromAccount.id, amount: decimalAmount, description: desc)
                }
                
                await MainActor.run {
                    isProcessing = false
                    resultMessage = "Transaction completed successfully!\nReference: \(accountManager.transactions.first?.referenceNumber ?? "N/A")"
                    resultIsSuccess = true
                    showResult = true
                }
            } catch {
                await MainActor.run {
                    isProcessing = false
                    resultMessage = error.localizedDescription
                    resultIsSuccess = false
                    showResult = true
                }
            }
        }
    }
}

// MARK: - Account Detail View

struct AccountDetailView: View {
    let account: Account
    @StateObject private var accountManager = AccountManager.shared
    
    var accountTransactions: [Transaction] {
        accountManager.getTransactions(forAccountId: account.id)
    }
    
    var body: some View {
        ScrollView {
            VStack(spacing: 20) {
                // Account Balance Header
                VStack(spacing: 8) {
                    Text("Available Balance")
                        .font(.subheadline)
                        .foregroundColor(.secondary)
                    
                    Text(account.formattedBalance)
                        .font(.system(size: 42, weight: .bold, design: .rounded))
                    
                    Text("Account: \(account.maskedAccountNumber)")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                .padding(.vertical, 20)
                
                // Transaction History
                VStack(alignment: .leading, spacing: 12) {
                    Text("Transaction History")
                        .font(.headline)
                    
                    if accountTransactions.isEmpty {
                        Text("No transactions for this account.")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                            .frame(maxWidth: .infinity, alignment: .center)
                            .padding()
                    } else {
                        ForEach(accountTransactions) { transaction in
                            TransactionRowView(transaction: transaction)
                            Divider()
                        }
                    }
                }
            }
            .padding()
        }
        .navigationTitle(account.accountHolderName)
        .navigationBarTitleDisplayMode(.inline)
    }
}

